"use strict";(()=>{document.addEventListener("DOMContentLoaded",()=>{let s=document.getElementById("apiUrl"),n=document.getElementById("persona"),a=document.getElementById("saveBtn"),e=document.getElementById("status");chrome.storage.sync.get(["apiUrl","persona"],t=>{s.value=t.apiUrl||"http://localhost:3000/api/generate",n.value=t.persona||""}),a.addEventListener("click",()=>{let t=s.value.trim(),o=n.value.trim();chrome.storage.sync.set({apiUrl:t,persona:o},()=>{e.textContent="Settings saved successfully!",e.className="status success",setTimeout(()=>{e.style.display="none",e.className="status"},3e3)})})});})();
